function _writeCheckpoint(address delegatee, uint32 nCheckpoints, uint96 oldVotes, uint96 newVotes) internal {
  uint32 blockNumber = safe32(block.number, "Comp::_writeCheckpoint: block number exceeds 32 bits");

  if (nCheckpoints > 0 && checkpoints[delegatee][nCheckpoints - 1].fromBlock == blockNumber) {
      checkpoints[delegatee][nCheckpoints - 1].votes = newVotes;
  } else {
      checkpoints[delegatee][nCheckpoints] = Checkpoint(blockNumber, newVotes);
      numCheckpoints[delegatee] = nCheckpoints + 1;
  }

  emit DelegateVotesChanged(delegatee, oldVotes, newVotes);
}

function queueTransaction(address target, uint value, string memory signature, bytes memory data, uint eta) public returns (bytes32) {
    require(msg.sender == admin, "Timelock::queueTransaction: Call must come from admin.");
    require(eta >= getBlockTimestamp().add(delay), "Timelock::queueTransaction: Estimated execution block must satisfy delay.");

    bytes32 txHash = keccak256(abi.encode(target, value, signature, data, eta));
    queuedTransactions[txHash] = true;

    emit QueueTransaction(txHash, target, value, signature, data, eta);
    return txHash;
}

function transferFrom(address src, address dst, uint wad)
        public returns (bool)
    {
        require(balanceOf[src] >= wad, "Dai/insufficient-balance");
        if (src != msg.sender && allowance[src][msg.sender] != uint(-1)) {
            require(allowance[src][msg.sender] >= wad, "Dai/insufficient-allowance");
            allowance[src][msg.sender] = sub(allowance[src][msg.sender], wad);
        }
        balanceOf[src] = sub(balanceOf[src], wad);
        balanceOf[dst] = add(balanceOf[dst], wad);
        emit Transfer(src, dst, wad);
        return true;
    }

function join(address usr, uint wad) external {
    require(live == 1, "GemJoin/not-live");
    require(int(wad) >= 0, "GemJoin/overflow");
    vat.slip(ilk, usr, int(wad));
    require(gem.transferFrom(msg.sender, address(this), wad), "GemJoin/failed-transfer");
    emit Join(usr, wad);
}
function exit(address usr, uint wad) external {
    require(wad <= 2 ** 255, "GemJoin/overflow");
    vat.slip(ilk, msg.sender, -int(wad));
    require(gem.transfer(usr, wad), "GemJoin/failed-transfer");
    emit Exit(usr, wad);
}

function beforeModifyLiquidity(
    IHooks self,
    PoolKey memory key,
    ModifyLiquidityParams memory params,
    bytes calldata hookData
) internal noSelfCall(self) {
    if (params.liquidityDelta > 0 && self.hasPermission(BEFORE_ADD_LIQUIDITY_FLAG)) {
        self.callHook(abi.encodeCall(IHooks.beforeAddLiquidity, (msg.sender, key, params, hookData)));
    } else if (params.liquidityDelta <= 0 && self.hasPermission(BEFORE_REMOVE_LIQUIDITY_FLAG)) {
        self.callHook(abi.encodeCall(IHooks.beforeRemoveLiquidity, (msg.sender, key, params, hookData)));
    }
}

for (uint256 pid = 0; pid < length; ++pid) {
    if (userInfo[pid][msg.sender].amount == 0 || poolInfos[pid].allocPoint == 0) {
        continue; // save gas
    }
    PoolInfo storage pool = poolInfos[pid];
    UserInfo storage user = userInfo[pid][msg.sender];
    updatePool(pid);
    pending = pending.add(
        DecimalMath.mulFloor(user.amount, pool.accDODOPerShare).sub(user.rewardDebt)
    );
    user.rewardDebt = DecimalMath.mulFloor(user.amount, pool.accDODOPerShare);
}

for (; !proof.done(); proof.next()) {
    bytes memory proofName = proof.name();
    if (!proofName.equals(rrset.signerName)) {
        revert ProofNameMismatch(rrset.signerName, proofName);
    }

    bytes memory keyrdata = proof.rdata();
    RRUtils.DNSKEY memory dnskey = keyrdata.readDNSKEY(
        0,
        keyrdata.length
    );
    if (verifySignatureWithKey(dnskey, keyrdata, rrset, data)) {
        return;
    }
}

if (allowance_.startDate == 0) {
    require(startDate_ > 0, "MultiTokenPeriodEnforcer:invalid-zero-start-date");
    require(periodAmount_ > 0, "MultiTokenPeriodEnforcer:invalid-zero-period-amount");
    require(periodDuration_ > 0, "MultiTokenPeriodEnforcer:invalid-zero-period-duration");
    require(block.timestamp >= startDate_, "MultiTokenPeriodEnforcer:transfer-not-started");

    allowance_.periodAmount = periodAmount_;
    allowance_.periodDuration = periodDuration_;
    allowance_.startDate = startDate_;
}

if (level == 3) {
    uint256 directUplinkId = accounts[nftId].directUplink;
    RewardAccountInfo storage directUplink = accounts[directUplinkId];
    if (block.timestamp < directUplink.bonusDeadline && !directUplink.accountLiquidated) {
        directUplink.activeBonusUsers++;
        if (directUplink.activeBonusUsers == 5) {

            directUplink.bonusActive = true;
            claimInitialFastStart(directUplink.ID);

            emit BonusActivated(nftId);
        }
    }
}

if (!markets[mToken].accountMembership[borrower]) {
    // only mTokens may call borrowAllowed if borrower not in market
    require(msg.sender == mToken, "sender must be mToken");

    // attempt to add borrower to the market
    Error addToMarketErr = addToMarketInternal(
        MToken(msg.sender),
        borrower
    );
    if (addToMarketErr != Error.NO_ERROR) {
        return uint(addToMarketErr);
    }

    // it should be impossible to break the important invariant
    assert(markets[mToken].accountMembership[borrower]);
}

if (isDebt) {
    if (debtPositions.length >= MAX_POSITIONS) revert Cellar__PositionArrayFull(MAX_POSITIONS);
    // Add new position at a specified index.
    debtPositions.add(index, positionId);
} else {
    if (creditPositions.length >= MAX_POSITIONS) revert Cellar__PositionArrayFull(MAX_POSITIONS);
    // Add new position at a specified index.
    creditPositions.add(index, positionId);
}

for (uint256 i; i < length; ) {
    uint256 share;
    address beneficiary = _beneficiaries[i];
    if (i == length - 1) {
        share = msg.value - totalDistribution; // leftover to last beneficiary
    } else {
        share = (msg.value * _sharesBps[beneficiary]) / MAX_BPS;
    }
    (bool success, ) = beneficiary.call{value: share}("");
    if (!success) revert FailedToSend();
    unchecked {
        totalDistribution += share;
        ++i;
    }
}

if (currentClaimPhase.merkleRoot != bytes32(0)) {
    (isOverride, ) = MerkleProof.verify(
        _allowlistProof.proof,
        currentClaimPhase.merkleRoot,
        keccak256(
            abi.encodePacked(
                _claimer,
                _allowlistProof.quantityLimitPerWallet,
                _allowlistProof.pricePerToken,
                _allowlistProof.currency
            )
        )
    );
}

if (state.selector == ITransformERC20Feature.transformERC20.selector) {
    returnResult = _executeTransformERC20Call(state);
} else if (state.selector == INativeOrdersFeature.fillLimitOrder.selector) {
    returnResult = _executeFillLimitOrderCall(state);
} else if (state.selector == INativeOrdersFeature.fillRfqOrder.selector) {
    returnResult = _executeFillRfqOrderCall(state);
} else {
    LibMetaTransactionsRichErrors.MetaTransactionUnsupportedFunctionError(state.hash, state.selector).rrevert();
}

if (fromToken != bnt) {
    (bool success, bytes memory data) = address(bancorConverterRegistry).staticcall.gas(100000)(abi.encodeWithSelector(
        bancorConverterRegistry.getConvertibleTokenSmartToken.selector,
        fromToken.isETH() ? ETH_ADDRESS : fromToken,
        0
    ));
    if (!success) {
        return new address[](0);
    }

    fromConverter = abi.decode(data, (address));
    if (fromConverter == address(0)) {
        return new address[](0);
    }
}

if (minReports > 0) {
  ISortedOracles sortedOracles = ISortedOracles(_oracleAddress);
  require(
    sortedOracles.numRates(sellTokenAddress) >= minReports,
    "Number of reports for token not enough"
  );

  (uint256 rateNumerator, uint256 rateDenominator) = oracle.getExchangeRate(sellTokenAddress);

  minimalSortedOracles = calculateMinAmount(
    rateNumerator,
    rateDenominator,
    amount,
    maxSlippage
  );
}

for (uint256 i = 0; i < delegatees.length; i = i.add(1)) {
  DelegatedInfo storage currentDelegateeInfo = delegated.delegateesWithPercentagesAndAmount[
    delegatees[i]
  ];
  (uint256 expected, uint256 real) = _getDelegatorDelegateeExpectedAndRealAmount(
    delegator,
    delegatees[i]
  );
  uint256 delegateeAmountToRevoke = FixidityLib
    .newFixed(amountToRevoke)
    .multiply(currentDelegateeInfo.percentage)
    .fromFixed();
  delegateeAmountToRevoke = delegateeAmountToRevoke.sub(expected.sub(real));
  _decreaseDelegateeVotingPower(delegatees[i], delegateeAmountToRevoke, currentDelegateeInfo);
  emit DelegatedCeloRevoked(delegator, delegatees[i], 0, delegateeAmountToRevoke);
}

if (deltaBlocks > 0 && supplySpeed > 0) {
    uint supplyTokens = CToken(cToken).totalSupply();
    uint compAccrued = mul_(deltaBlocks, supplySpeed);
    Double memory ratio = supplyTokens > 0 ? fraction(compAccrued, supplyTokens) : Double({mantissa: 0});
    supplyState.index = safe224(add_(Double({mantissa: supplyState.index}), ratio).mantissa, "new index exceeds 224 bits");
    supplyState.block = blockNumber;
} else if (deltaBlocks > 0) {
    supplyState.block = blockNumber;
}

if (deltaBlocks > 0 && borrowSpeed > 0) {
    uint borrowAmount = div_(CToken(cToken).totalBorrows(), marketBorrowIndex);
    uint compAccrued = mul_(deltaBlocks, borrowSpeed);
    Double memory ratio = borrowAmount > 0 ? fraction(compAccrued, borrowAmount) : Double({mantissa: 0});
    borrowState.index = safe224(add_(Double({mantissa: borrowState.index}), ratio).mantissa, "new index exceeds 224 bits");
    borrowState.block = blockNumber;
} else if (deltaBlocks > 0) {
    borrowState.block = blockNumber;
}

if (balance > 0) {
  // If the allowance is insufficient, set it before depositing.
  if (cToken.allowance(address(this), address(dToken)) < balance) {
    require(cToken.approve(address(dToken), uint256(-1)), _revertReason(23));
  }

  // Deposit the new balance on the Dharma Token.
  require(dToken.mintViaCToken(balance) > 0, _revertReason(24));
}

if (!alreadyAccrued) {
  // Update storage with dToken + cToken exchange rates as of current block.
  AccrualIndex storage accrualIndex = _accrualIndex;
  accrualIndex.dTokenExchangeRate = _safeUint112(dTokenExchangeRate);
  accrualIndex.cTokenExchangeRate = _safeUint112(cTokenExchangeRate);
  accrualIndex.block = uint32(block.number);
  emit Accrue(dTokenExchangeRate, cTokenExchangeRate);
}

if (size >= 4) {
    bytes memory errorId = LowLevelCallUtils.readReturnData(0, 4);
    if (bytes4(errorId) == OffchainLookup.selector) {
        // Offchain lookup. Decode the revert message and create our own that nests it.
        bytes memory revertData = LowLevelCallUtils.readReturnData(
            4,
            size - 4
        );
        handleOffchainLookupError(revertData, target, name);
    }
}

if (exponentLen != 0) {
    exponent = key.substring(5, exponentLen);
    modulus = key.substring(
        exponentLen + 5,
        key.length - exponentLen - 5
    );
} else {
    exponentLen = key.readUint16(5);
    exponent = key.substring(7, exponentLen);
    modulus = key.substring(
        exponentLen + 7,
        key.length - exponentLen - 7
    );
}

for (uint256 j = 0; j < operators.length; j++) {
    address operator = operators[j];
    uint256 reward = intervalRewards[interval][address(strategy)][operator];
    if (reward > 0) {
        totalRewards += reward;
    }
    operatorRewards[j] = IRewardsCoordinatorTypes.OperatorReward({
        operator: operator,
        amount: reward
    });
}

if (__DEPRECATED__collectModuleWhitelisted[msg.sender]) {
    // This state was pre-filled at LegacyCollectLib and it is a hack to make legacy collect work when
    // configured for followers only.
    return
        _legacyCollectFollowValidationHelper[followerAddress] == followedProfileId ||
        ProfileLib.isExecutorApproved(followedProfileId, followerAddress) ||
        ProfileLib.ownerOf(followedProfileId) == followerAddress;
} else {
    revert Errors.ExecutorInvalid();
}

for (uint i = 0; i < orderAddresses.length; i++) {
    require(orderAddresses[i][3] == orderAddresses[0][3]); // takerToken must be the same for each order
    filledTakerTokenAmount = safeAdd(filledTakerTokenAmount, fillOrder(
        orderAddresses[i],
        orderValues[i],
        safeSub(fillTakerTokenAmount, filledTakerTokenAmount),
        shouldThrowOnInsufficientBalanceOrAllowance,
        v[i],
        r[i],
        s[i]
    ));
    if (filledTakerTokenAmount == fillTakerTokenAmount) break;
}

for (uint256 i = 0; i < caveatsLength_; ++i) {
    Address.functionCall(
        caveatGroup_.caveats[i].enforcer,
        abi.encodeWithSelector(
            _hookSelector,
            caveatGroup_.caveats[i].terms,
            selectedGroup_.caveatArgs[i],
            _params.mode,
            _params.executionCallData,
            _params.delegationHash,
            _params.delegator,
            _params.redeemer
        )
    );
}

if (proxy == address(0) || ProxyLike(proxy).owner() != dst) {
    uint256 csize;
    assembly {
        csize := extcodesize(dst)
    }
    // We want to avoid creating a proxy for a contract address that might not be able to handle proxies, then losing the CDP
    require(csize == 0, "Dst-is-a-contract");
    // Creates the proxy for the dst address
    proxy = ProxyRegistryLike(proxyRegistry).build(dst);
}

if (!getCorePoolMarket(vToken).accountMembership[borrower]) {
    // only vTokens may call borrowAllowed if borrower not in market
    require(msg.sender == vToken, "sender must be vToken");

    // attempt to add borrower to the market
    Error err = addToMarketInternal(VToken(vToken), borrower);
    if (err != Error.NO_ERROR) {
        return uint256(err);
    }
}

returnResult = _callSelf(
    state.hash,
    abi.encodeWithSelector(
        IMultiplexFeature._multiplexBatchSell.selector,
        IMultiplexFeature.BatchSellParams({
            inputToken: inputToken,
            outputToken: IERC20Token(WETH),
            sellAmount: sellAmount,
            calls: calls,
            useSelfBalance: false,
            recipient: address(this),
            payer: state.mtx.signer
        }),
        minBuyAmount
    )
);
